/**
 * DashboardPage.js
 * Routes worker vs seeker to appropriate dashboard.
 * Admins get link to admin panel.
 */
import React from 'react';
import { Navigate, Link } from 'react-router-dom';
import { useAuth } from '../../context/AuthContext';
import WorkerDashboard from '../worker/WorkerDashboard';
import SeekerDashboard from '../seeker/SeekerDashboard';

const DashboardPage = () => {
  const { user, isWorker, isSeeker, isAdmin } = useAuth();
  if (!user) return <Navigate to="/login" replace />;
  if (isAdmin)  return (
    <div style={{ textAlign:'center', padding:40 }}>
      <div style={{ fontSize:48 }}>🛡</div>
      <h2>Admin Panel</h2>
      <Link to="/admin" style={{ padding:'12px 24px', background:'#6366f1', color:'#fff', borderRadius:10, textDecoration:'none', fontWeight:600 }}>
        Go to Admin Dashboard →
      </Link>
    </div>
  );
  if (isWorker) return <WorkerDashboard />;
  if (isSeeker) return <SeekerDashboard />;
  return <Navigate to="/login" replace />;
};

export default DashboardPage;
